// MsgServer is the server API for Msg service.
type MsgServer interface {
	// RegisterInstitution adds an institution after the 6 criteria are met — operator/company only.
	RegisterInstitution(context.Context, *MsgRegisterInstitution) (*MsgRegisterInstitutionResponse, error)
	// RemoveInstitution removes after an orderly wind-down — operator/company only.
	RemoveInstitution(context.Context, *MsgRemoveInstitution) (*MsgRemoveInstitutionResponse, error)
	// InstitutionMint mints only against an attested deposit; conditioned on that institution's attested reserve.
	InstitutionMint(context.Context, *MsgInstitutionMint) (*MsgInstitutionMintResponse, error)
	// InstitutionRedeem burns/redeems; conditioned on vault_balance ≥ amount; no inter-institution settlement.
	InstitutionRedeem(context.Context, *MsgInstitutionRedeem) (*MsgInstitutionRedeemResponse, error)
	// PublishInstitutionAttestation publishes the live vault reserve/reconciliation attestation.
	PublishInstitutionAttestation(context.Context, *MsgPublishInstitutionAttestation) (*MsgPublishInstitutionAttestationResponse, error)
	// FreezeInstitution halts minting on reconciliation divergence — company/automated.
	FreezeInstitution(context.Context, *MsgFreezeInstitution) (*MsgFreezeInstitutionResponse, error)
	// UpdateParams — governance only.
	UpdateParams(context.Context, *MsgUpdateParams) (*MsgUpdateParamsResponse, error)
	// SetEmergencyRedemption activates/deactivates the network-wide stepped-redemption brake — governance only.
	SetEmergencyRedemption(context.Context, *MsgSetEmergencyRedemption) (*MsgSetEmergencyRedemptionResponse, error)
	// GrantInstitutionRole grants a sub-organization role (RBAC §13.1) — sensitive.
	GrantInstitutionRole(context.Context, *MsgGrantInstitutionRole) (*MsgGrantInstitutionRoleResponse, error)
	// RevokeInstitutionRole revokes a sub-organization role — sensitive.
	RevokeInstitutionRole(context.Context, *MsgRevokeInstitutionRole) (*MsgRevokeInstitutionRoleResponse, error)
	// UpdateInstitutionAppConfig toggles app services/widgets + the vault scan link (§13.2) — sensitive.
	UpdateInstitutionAppConfig(context.Context, *MsgUpdateInstitutionAppConfig) (*MsgUpdateInstitutionAppConfigResponse, error)
	// UpdateInstitutionParams operational parameters + risk rules (§13.3, only stricter) — sensitive.
	UpdateInstitutionParams(context.Context, *MsgUpdateInstitutionParams) (*MsgUpdateInstitutionParamsResponse, error)
	// SetInstitutionDepositKey sets the institution's P-256 deposit-signing key (provably-backed mint) — sensitive.
	SetInstitutionDepositKey(context.Context, *MsgSetInstitutionDepositKey) (*MsgSetInstitutionDepositKeyResponse, error)
	// RequestFxEntry: an exchange applies to join, naming an active financial guarantor.
	RequestFxEntry(context.Context, *MsgRequestFxEntry) (*MsgRequestFxEntryResponse, error)
	// GuaranteeFxEntry: the named financial institution's admin approves/declines the guarantee.
	GuaranteeFxEntry(context.Context, *MsgGuaranteeFxEntry) (*MsgGuaranteeFxEntryResponse, error)
	// FinalizeFxEntry: finalizes onboarding after a passed public vote (or direct operator add during bootstrap).
	FinalizeFxEntry(context.Context, *MsgFinalizeFxEntry) (*MsgFinalizeFxEntryResponse, error)
}

